xml.src:

import {InuFooter} from 'inugami-ng/components/inu-footer';

@Component({
  selector: 'app-root',
             imports: [
               RouterOutlet,
               InuFooter
             ],
  templateUrl: './app.html',
  styleUrl: './app.scss'
})
export class App {
  // implementation ...
}


import {provideCacheTracking} from 'inugami-ng/services';

const APPLICATION = signal<string>('inugami-ng');
const ENV         = signal<string>('PRD');
const SESSION_UID = signal<string>(UuidUtils.buildUid());
const VERSION     = signal<string>('0.0.18');


export const appConfig: ApplicationConfig = {
  providers: [
    provideCacheTracking({
                           env        : ENV,
                           sessionUid : SESSION_UID,
                           application: APPLICATION,
                           version    : VERSION
                         })
  ]
};
